import React, { useEffect, useMemo, useState } from 'react';
import { masterService } from '../../../services/master/masterService';
import {
  Input,
  Button,
  Checkbox,
  SearchInput,
  Select,
  Slideout,
  useDirtyTracking,
  type OnDirtyChange,
} from '@linm-soft-org/linm-web-common-components';
import type { CustomerDto, CustomerListItemDto } from '../../../services/master/models';
import { normalizeCode, normalizeCodeOptional } from '../../../utils/codeField';
import { createAccountSearchConfig, formatAccountDisplay } from '../../search';
import {
  CatalogCompanyField,
  CatalogFormFooter,
  CatalogFormHistorySlot,
  CatalogLegacyCodeSuffix,
  SharedCatalogFormActions,
  isSharedCatalogReadOnly,
} from '../../catalog';
import type { SharedCatalogFormIntegrationProps } from '../../catalog';
import styles from '../../../styles/erpPage.module.css';
import df from '../../../styles/documentForm.module.css';
import { CustomerParentLookupField } from '../customer/CustomerParentLookupField';
import { CustomerGroupLookupField } from '../customerGroup/CustomerGroupLookupField';
import { useCustomerGroupFormFields } from '../../../hooks/useCustomerGroupFormFields';
import {
  customerGroupLevelKeys,
  getCustomerTypeSelectFallback,
  isManualCustomerCodeType,
} from '../../../utils/customerGroupTree';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { selectPlaceholderClass } from '../../../utils/selectField';
import {
  useCustomerForm,
  type CustomerFormState,
  type UseCustomerFormOptions,
} from './useCustomerForm';
import { CustomerViewDetail, extractDetailGrids } from './CustomerViewDetail';
import { CustomerSupplierEditSection } from './CustomerSupplierEditSection';
import {
  isSupplierLikeCustomerType,
  type CustomerBankAccountLine,
  type CustomerDiscountTermLine,
} from '../../../services/master/customerDetailModels';

export interface CustomerFormProps extends UseCustomerFormOptions {
  testIdPrefix: string;
  companyName?: string;
  hideCompanyField?: boolean;
  /** FormMode.View — readonly active style, footer Đóng + Lịch sử only */
  readOnly?: boolean;
  sharedCatalog?: SharedCatalogFormIntegrationProps;
  onCancel: () => void;
  onValidationFailed?: () => void;
  onDirtyChange?: OnDirtyChange;
  /** Slideout shell — list page; default inline (parcel). */
  shellVariant?: 'inline' | 'slideout';
  slideoutOpen?: boolean;
  slideoutTitle?: string;
  slideoutWidth?: string;
}

/** Form tạo/sửa/xem đối tượng — catalog + search parcel. */
export const CustomerForm: React.FC<CustomerFormProps> = ({
  testIdPrefix,
  editing = null,
  initialName,
  defaultCustomerType,
  defaultCustomerGroupId,
  defaultParentCustomer = null,
  initFormName,
  listGroupOptions,
  companyName,
  hideCompanyField = false,
  readOnly: isViewMode = false,
  sharedCatalog,
  onCancel,
  onSaved,
  onValidationFailed,
  onDirtyChange,
  shellVariant = 'inline',
  slideoutOpen = false,
  slideoutTitle = '',
  slideoutWidth = '720px',
}) => {
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const { fields: groupFormFields, loading: groupFieldsLoading } = useCustomerGroupFormFields();
  const [accountName, setAccountName] = useState('');
  const [bankLines, setBankLines] = useState<CustomerBankAccountLine[]>([]);
  const [discountLines, setDiscountLines] = useState<CustomerDiscountTermLine[]>([]);
  const [detailLoaded, setDetailLoaded] = useState(false);
  const {
    form,
    setForm,
    errors,
    saving,
    codePlaceholder,
    clearFieldError,
    applyGroupLevelSelection,
    clearGroupFromLevel,
    applyParentSelection,
    clearParentSelection,
    parentGroupLockDepth,
    presetGroupLockDepth,
    handleSave,
  } = useCustomerForm({
    editing,
    initialName,
    defaultCustomerType,
    defaultCustomerGroupId,
    defaultParentCustomer,
    initFormName,
    listGroupOptions,
    onSaved,
    markClean,
    bankLines,
    discountLines,
  });

  const sharedReadOnlyRow = editing ? isSharedCatalogReadOnly(editing) : false;
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const editingCustomerId = editing?.customerId;

  /** Chỉ reset grid khi chuyển sang tạo mới — không chạy lại khi user thêm/xóa dòng. */
  useEffect(() => {
    if (editingCustomerId) return;
    setBankLines([]);
    setDiscountLines([]);
    setDetailLoaded(false);
  }, [editingCustomerId]);

  /** Load STK + chiết khấu khi mở sửa/xem — phụ thuộc customerId, không phụ thuộc setForm. */
  useEffect(() => {
    if (!editingCustomerId) return;

    let cancelled = false;
    setDetailLoaded(false);
    const t = setTimeout(() => {
      masterService.getCustomerById(editingCustomerId)
        .then(detail => {
          if (cancelled) return;
          const raw = detail as unknown as Record<string, unknown>;
          const grids = extractDetailGrids(raw);
          setBankLines(grids.bankLines);
          setDiscountLines(grids.discountLines);
          setForm(f =>
            f.customerId === detail.customerId
              ? { ...f, ...detail }
              : { ...detail },
          );
          setDetailLoaded(true);
        })
        .catch(() => {
          if (!cancelled) setDetailLoaded(true);
        });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [editingCustomerId, setForm]);

  /** Cấp 1 = không có đối tượng cha (root). */
  const isRootCustomer = editing ? !editing.parentId : !form.parentId;
  const isEditMode = !!editing && !isViewMode;
  /** Sửa/xem cấp 1 — ẩn lookup cha; tạo mới luôn hiện. */
  const showParentField = !editing || !isRootCustomer;
  /** Sửa — không đổi cha; xem — readonly. */
  const parentFieldDisabled = isViewMode || isEditMode;
  /** Sửa đối tượng cấp 1 — khóa nhóm 1 (đã gắn khi tạo). */
  const lockGroup1OnEdit = isEditMode && isRootCustomer;

  useEffect(() => {
    if (!form.accountCode?.trim()) {
      setAccountName('');
      return;
    }
    let cancelled = false;
    masterService.getAccounts({ search: form.accountCode, page: 1, pageSize: 5, isActive: true })
      .then(res => {
        if (cancelled) return;
        const a = res.items.find(x => x.code === form.accountCode);
        setAccountName(a?.name ?? '');
      })
      .catch(() => { if (!cancelled) setAccountName(''); });
    return () => { cancelled = true; };
  }, [form.accountCode]);

  const onSaveClick = async () => {
    const ok = await handleSave();
    if (!ok && onValidationFailed) onValidationFailed();
  };

  const formGridClass = isViewMode
    ? `${styles.formGrid} ${styles.viewReadOnlySection}`
    : styles.formGrid;

  const groupLevelError = errors.customerGroupId;

  const {
    customerTypeOptions: initCustomerTypeOptions,
    paymentMethodOptions,
    legalTypeOptions,
    vatRegisteredOptions,
    customerBankAccountKindOptions,
  } = useVoucherInitData(initFormName ?? 'create-customer');
  const customerTypeOpts = useMemo(
    () => (initCustomerTypeOptions.length > 0 ? initCustomerTypeOptions : getCustomerTypeSelectFallback()),
    [initCustomerTypeOptions],
  );
  const customerTypeLocked = isViewMode || !!form.parentId;
  const manualCustomerCode = isManualCustomerCodeType(form.customerType);
  const showSupplierDetail = isSupplierLikeCustomerType(form.customerType);
  const detailLoading = !!editingCustomerId && !detailLoaded;

  const footerVariant = shellVariant === 'slideout' ? 'slideout' : 'modal';

  const formBody = (
    <div className={formGridClass} aria-busy={detailLoading || undefined}>
        {detailLoading ? (
          <p className={styles.formGridFullRow} data-testid={`${testIdPrefix}-detail-loading`}>
            Đang tải chi tiết…
          </p>
        ) : null}
        <div
          className={`${styles.formGridFullRow} ${styles.field}`}
          data-testid={`${testIdPrefix}-field-customerType`}
        >
          <label className={styles.label}>Loại đối tượng *</label>
          <Select
            value={form.customerType ?? ''}
            placeholder="— Chọn loại —"
            disabled={customerTypeLocked}
            error={errors.customerType}
            className={selectPlaceholderClass(form.customerType)}
            onChange={e => {
              if (customerTypeLocked) return;
              markDirty();
              clearFieldError('customerType');
              setForm(f => ({ ...f, customerType: e.target.value }));
            }}
            options={customerTypeOpts}
          />
        </div>
        <div className={styles.masterCodeNameRow}>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-code`}>
            <label className={styles.label}>Mã đối tượng *</label>
            {editing || isViewMode ? (
              <Input
                value={form.code ?? ''}
                readOnly
                error={errors.code}
                className={styles.codeInput}
              />
            ) : manualCustomerCode ? (
              <Input
                value={form.code ?? ''}
                error={errors.code}
                placeholder="Nhập mã khách hàng"
                className={styles.codeInput}
                data-testid={`${testIdPrefix}-field-code-input`}
                onChange={e => {
                  markDirty();
                  clearFieldError('code');
                  setForm(f => ({ ...f, code: e.target.value }));
                }}
              />
            ) : (
              <Input
                value=""
                readOnly
                disabled
                error={errors.code}
                placeholder={codePlaceholder}
                className={styles.codeInput}
                data-testid={`${testIdPrefix}-code-preview`}
              />
            )}
            <CatalogLegacyCodeSuffix
              testIdPrefix={testIdPrefix}
              code={editing?.code}
              legacyCode={editing?.legacyCode}
            />
          </div>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-name`}>
            <label className={styles.label}>Tên đối tượng *</label>
            <Input
              value={form.name ?? ''}
              readOnly={isViewMode}
              error={errors.name}
              onChange={e => {
                markDirty();
                clearFieldError('name');
                setForm(f => ({ ...f, name: e.target.value }));
              }}
            />
          </div>
        </div>
        {showParentField ? (
          <div
            className={`${styles.formGridFullRow} ${styles.field}`}
            data-testid={`${testIdPrefix}-field-parentId`}
          >
            <label className={styles.label}>Đối tượng cha</label>
            <CustomerParentLookupField
              parentId={form.parentId}
              parentCode={form.parentCode}
              parentName={form.parentName}
              excludeCustomerId={editing?.customerId}
              disabled={parentFieldDisabled}
              onChange={parent => {
                if (parentFieldDisabled) return;
                markDirty();
                applyParentSelection(parent);
              }}
              onClear={() => {
                if (parentFieldDisabled) return;
                markDirty();
                clearParentSelection();
              }}
              testId={`${testIdPrefix}-parent`}
            />
          </div>
        ) : null}
        <div
          className={`${styles.formGridFullRow} ${df.row4}`}
          data-testid={`${testIdPrefix}-customer-group-cascade`}
        >
          {groupFormFields.map(field => {
            const keys = customerGroupLevelKeys(field.level);
            const codeKey = keys.codeKey;
            const nameKey = keys.nameKey;
            const parentGroupIdForLookup =
              field.level > 1
                ? String(
                    form[customerGroupLevelKeys(field.level - 1).idKey as keyof CustomerFormState] ?? '',
                  ) || undefined
                : undefined;
            const showLevelError = field.level === 1 && groupLevelError;
            const groupLockedByParent =
              !!form.parentId && field.level <= parentGroupLockDepth;
            const groupLockedByPreset =
              !editing && !form.parentId && field.level <= presetGroupLockDepth;
            const groupLockedOnEdit =
              lockGroup1OnEdit && field.level === 1;
            return (
              <div key={field.key} className={styles.field} data-testid={`${testIdPrefix}-field-${codeKey}`}>
                <label className={styles.label}>
                  {field.label}
                  {field.level === 1 ? ' *' : ''}
                </label>
                <CustomerGroupLookupField
                  level={field.level}
                  parentGroupId={parentGroupIdForLookup}
                  value={String(form[codeKey as keyof CustomerFormState] ?? '')}
                  displayName={String(form[nameKey as keyof CustomerFormState] ?? '')}
                  disabled={
                    isViewMode
                    || groupFieldsLoading
                    || groupLockedByParent
                    || groupLockedByPreset
                    || groupLockedOnEdit
                  }
                  error={showLevelError ? groupLevelError : undefined}
                  onChange={(code, name, groupId) => {
                    markDirty();
                    applyGroupLevelSelection(field.level, code, name, groupId);
                  }}
                  onClear={() => {
                    if (groupLockedOnEdit) return;
                    markDirty();
                    clearGroupFromLevel(field.level);
                    clearFieldError('customerGroupId');
                  }}
                  testId={`${testIdPrefix}-group-${field.level}`}
                />
              </div>
            );
          })}
        </div>
        <div className={styles.masterCodeNameRow}>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-taxCode`}>
            <label className={styles.label}>Mã số thuế</label>
            <Input
              value={form.taxCode ?? ''}
              readOnly={isViewMode}
              className={styles.codeInput}
              onChange={e => {
                markDirty();
                setForm(f => ({ ...f, taxCode: normalizeCodeOptional(e.target.value) }));
              }}
            />
          </div>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-phone`}>
            <label className={styles.label}>Số điện thoại</label>
            <Input
              value={form.phone ?? ''}
              readOnly={isViewMode}
              onChange={e => {
                markDirty();
                setForm(f => ({ ...f, phone: e.target.value }));
              }}
            />
          </div>
        </div>
        <div
          className={`${styles.formGridFullRow} ${styles.field}`}
          data-testid={`${testIdPrefix}-field-address`}
        >
          <label className={styles.label}>Địa chỉ</label>
          <Input
            value={form.address ?? ''}
            readOnly={isViewMode}
            onChange={e => {
              markDirty();
              setForm(f => ({ ...f, address: e.target.value }));
            }}
          />
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-accountCode`}>
          <label className={styles.label}>Tài khoản công nợ</label>
          <SearchInput
            config={accountSearchConfig}
            value={form.accountCode ?? ''}
            primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
            disabled={isViewMode}
            onChange={a => {
              markDirty();
              setForm(f => ({ ...f, accountCode: a.code }));
              setAccountName(a.name ?? '');
            }}
            onClear={() => {
              markDirty();
              setForm(f => ({ ...f, accountCode: undefined }));
              setAccountName('');
            }}
            showLabel={false}
            showSecondaryInput={false}
            placeholder="Mã hoặc tên TK..."
          />
        </div>
    </div>
  );

  const formExtras = (
    <>
      {showSupplierDetail && isViewMode && editing ? (
        <CustomerViewDetail
          testIdPrefix={testIdPrefix}
          form={form}
          bankLines={bankLines}
          discountLines={discountLines}
          detailLoading={!detailLoaded}
          paymentMethodOptions={paymentMethodOptions}
          legalTypeOptions={legalTypeOptions}
          vatRegisteredOptions={vatRegisteredOptions}
          bankKindOptions={customerBankAccountKindOptions}
        />
      ) : null}
      {showSupplierDetail && !isViewMode ? (
        <CustomerSupplierEditSection
          testIdPrefix={testIdPrefix}
          form={form}
          setForm={setForm}
          markDirty={markDirty}
          bankLines={bankLines}
          discountLines={discountLines}
          onBankLinesChange={rows => {
            markDirty();
            setBankLines(rows);
          }}
          onDiscountLinesChange={rows => {
            markDirty();
            setDiscountLines(rows);
          }}
          supplierCustomerId={editing?.customerId}
          paymentMethodOptions={paymentMethodOptions}
          legalTypeOptions={legalTypeOptions}
          vatRegisteredOptions={vatRegisteredOptions}
          bankKindOptions={customerBankAccountKindOptions}
        />
      ) : null}
      {sharedCatalog && (!isViewMode || sharedReadOnlyRow) ? (
        <SharedCatalogFormActions
          testIdPrefix={testIdPrefix}
          row={editing}
          currentValues={{
            name: form.name,
            taxCode: form.taxCode,
            phone: form.phone,
            isActive: form.isActive,
          }}
          {...sharedCatalog}
        />
      ) : null}
    </>
  );

  const formFooter = isViewMode ? (
    <div className={styles.viewReadOnlySection}>
      {!hideCompanyField && (
        <CatalogCompanyField testIdPrefix={testIdPrefix} companyName={companyName} />
      )}
      <div className={styles.modalFooterBar} data-testid={`${testIdPrefix}-view-footer`}>
        <div className={styles.modalFooterActive} data-testid={`${testIdPrefix}-field-isActive`}>
          <Checkbox
            label="Đang sử dụng"
            checked={form.isActive ?? true}
            readOnly
            onChange={() => { /* view — không đổi */ }}
          />
        </div>
      </div>
      <div className={styles.modalActionsView}>
        <CatalogFormHistorySlot
          testIdPrefix={testIdPrefix}
          catalogKind="customers"
          editing={editing ? { id: editing.customerId, code: editing.code } : null}
        />
        <Button variant="secondary" onClick={onCancel} data-testid={`${testIdPrefix}-btn-close`}>
          Đóng
        </Button>
      </div>
    </div>
  ) : (
    <CatalogFormFooter
      companyName={companyName}
      testIdPrefix={testIdPrefix}
      variant={footerVariant}
      checked={form.isActive ?? true}
      onActiveChange={c => {
        markDirty();
        setForm(f => ({ ...f, isActive: c }));
      }}
      onCancel={onCancel}
      onSave={() => { void onSaveClick(); }}
      saving={saving}
      hideCompanyField={hideCompanyField}
      saveDisabled={sharedReadOnlyRow || detailLoading}
      activeDisabled={sharedReadOnlyRow}
      historySlot={
        <CatalogFormHistorySlot
          testIdPrefix={testIdPrefix}
          catalogKind="customers"
          editing={editing ? { id: editing.customerId, code: editing.code } : null}
        />
      }
    />
  );

  const formContent = (
    <div className={styles.modalBody} data-testid={`${testIdPrefix}-form`}>
      {formBody}
      {formExtras}
      {shellVariant === 'inline' ? formFooter : null}
    </div>
  );

  if (shellVariant === 'slideout') {
    return (
      <Slideout
        isOpen={slideoutOpen}
        onClose={onCancel}
        title={slideoutTitle}
        width={slideoutWidth}
        data-testid={`${testIdPrefix}-slideout`}
        customFooter={formFooter}
      >
        {formContent}
      </Slideout>
    );
  }

  return (
    <>
      {formContent}
    </>
  );
};

export type { CustomerDto };
