import React, { useMemo } from 'react';
import { SearchInput } from '@linm-soft-org/linm-web-common-components';
import { createCustomerSearchConfig } from '../../search/customerSearchConfig';
import type { CustomerDto } from '../../../services/master/models';

type Props = {
  parentId?: string;
  parentCode?: string;
  parentName?: string;
  excludeCustomerId?: string;
  disabled?: boolean;
  onChange: (parent: CustomerDto) => void;
  onClear: () => void;
  testId?: string;
};

/** Lookup đối tượng cha — 2 ô Mã + Tên (parity CustomerSearchField / phiếu thu). */
export const CustomerParentLookupField: React.FC<Props> = ({
  parentId,
  parentCode,
  parentName,
  excludeCustomerId,
  disabled,
  onChange,
  onClear,
  testId,
}) => {
  const config = useMemo(
    () => createCustomerSearchConfig({ excludeCustomerId }),
    [excludeCustomerId],
  );

  return (
    <SearchInput
      config={config}
      value={parentId ?? ''}
      primaryDisplay={parentCode ?? ''}
      secondaryDisplay={parentName ?? ''}
      onChange={onChange}
      onClear={onClear}
      disabled={disabled}
      showLabel={false}
      placeholder="Mã đối tượng cha..."
      data-testid={testId}
    />
  );
};
