/** Row snapshot for toolbar / list «Đề xuất» (existing record only). */
export interface SharedCatalogProposalRow {
  code: string;
  name?: string;
  isActive?: boolean;
  isReadOnly?: boolean;
  scope?: string;
}

export function proposalValuesFromRow(
  row: SharedCatalogProposalRow,
): Record<string, unknown> {
  return {
    name: row.name,
    isActive: row.isActive,
  };
}
