import { useMemo } from 'react';
import { useCatalogUiSchema } from '../components/catalog/catalogUiSchema/useCatalogUiSchema';

const GROUP_KEY_RE = /^customerGroup([1-4])Code$/;

export type CustomerGroupFormField = {
  level: number;
  key: string;
  label: string;
  order: number;
};

const DEFAULT_GROUP_FORM_FIELDS: CustomerGroupFormField[] = [1, 2, 3, 4].map(level => ({
  level,
  key: `customerGroup${level}Code`,
  label: `Nhóm đối tượng ${level}`,
  order: 100 + level * 10,
}));

export const CUSTOMERS_CATALOG_KIND = 'customers';

/** Form đối tượng — label 4 cấp nhóm theo ui-schema customers (form.visible / order). */
export function useCustomerGroupFormFields(catalogKind = CUSTOMERS_CATALOG_KIND) {
  const { schema, loading, reload } = useCatalogUiSchema(catalogKind);

  const fields = useMemo((): CustomerGroupFormField[] => {
    const fromSchema = (schema?.fields ?? [])
      .filter(f => GROUP_KEY_RE.test(f.key) && f.form?.visible !== false)
      .map(f => {
        const level = Number(GROUP_KEY_RE.exec(f.key)?.[1] ?? 0);
        return {
          level,
          key: f.key,
          label: f.label,
          order: f.form?.order ?? level * 10,
        };
      })
      .filter(f => f.level > 0)
      .sort((a, b) => a.order - b.order);

    return fromSchema.length > 0 ? fromSchema : DEFAULT_GROUP_FORM_FIELDS;
  }, [schema]);

  return { fields, loading, reload };
}
