import React, { useCallback, useMemo } from 'react';
import { SearchInput, type SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { masterService } from '../../../services/master/masterService';
import type { CustomerGroupDto } from '../../../services/master/models';

type Props = {
  level: number;
  value: string;
  displayName?: string;
  /** Nhóm cha cấp trước — lọc con + nhóm cùng cấp không parent. */
  parentGroupId?: string;
  disabled?: boolean;
  error?: string;
  onChange: (code: string, name: string, groupId: string) => void;
  onClear: () => void;
  testId?: string;
};

function buildFallbackGroupSearchConfig(
  level: number,
  search: (params: { search?: string; page?: number; pageSize?: number }) => ReturnType<
    typeof masterService.getCustomerGroups
  >,
): SearchInputConfig<CustomerGroupDto> {
  return {
    api: {
      getItemKey: item => item.customerGroupId,
      search: async ({ search: term, page, pageSize }) => {
        const data = await search({ search: term, page, pageSize });
        const size = data.pageSize || 20;
        const totalPages = Math.max(1, Math.ceil(data.totalCount / size));
        return { items: data.items, page: data.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
    columns: [
      {
        key: 'code',
        variant: 'badge',
        width: '7rem',
        render: item => item.code || '—',
      },
      {
        key: 'name',
        variant: 'primary',
        render: item => item.name || '—',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã nhóm' },
        { key: 'name', label: 'Tên nhóm' },
      ],
    },
    dropdownMatch: 'row',
    dropdownMinWidth: '22rem',
    dropdownPortal: true,
    texts: { empty: 'Không có nhóm nào' },
  };
}

/** Lookup nhóm đối tượng theo cấp 1–4 — cascade parentId (Step 5b catalog tree). */
export const CustomerGroupLookupField: React.FC<Props> = ({
  level,
  value,
  displayName,
  parentGroupId,
  disabled,
  error,
  onChange,
  onClear,
  testId,
}) => {
  const search = useCallback(
    (params: { search?: string; page?: number; pageSize?: number }) =>
      masterService.getCustomerGroups({
        level,
        search: params.search,
        isActive: true,
        parentId: parentGroupId || undefined,
        page: params.page,
        pageSize: params.pageSize,
      }),
    [level, parentGroupId],
  );

  const effectiveConfig = useMemo(
    () => buildFallbackGroupSearchConfig(level, search),
    [level, search],
  );

  const primaryDisplay = useMemo(() => {
    if (!value) return '';
    return displayName ? `${value} — ${displayName}` : value;
  }, [value, displayName]);

  return (
    <SearchInput
      config={effectiveConfig}
      value={value}
      primaryDisplay={primaryDisplay}
      onChange={item =>
        onChange(String(item.code), String(item.name), String(item.customerGroupId))
      }
      onClear={onClear}
      disabled={disabled}
      error={error}
      showLabel={false}
      showSecondaryInput={false}
      placeholder="Mã hoặc tên nhóm..."
      data-testid={testId}
    />
  );
};
